 14→/// Re-infer `"type"` from `"enum"` values when canonicalization stripped it.
 15→///
 16→/// `json_schema_ast` canonicalization removes redundant `"type"` annotations
 17→/// when all enum values match the declared type (`lower_enum_with_type`), and
 18→/// converts `"type": "boolean"` → `"enum": [false, true]`
 19→/// (`lower_boolean_and_null_types`). This is correct per JSON Schema semantics
 20→/// but providers like Fireworks AI reject schemas without explicit `"type"`.
 21→///
 22→/// This transform walks every schema node and restores `"type"` when:
 23→/// - `"enum"` is present but `"type"` is absent
 24→/// - All non-null enum values share a single JSON type
 25→#[derive(Debug, Clone, Default)]
 26→struct RestoreEnumTypeTransform;
 27→
 28→impl Transform for RestoreEnumTypeTransform {
 29→    fn transform(&mut self, schema: &mut Schema) {
 30→        let Some(obj) = schema.as_object_mut() else {
 31→            return;
 32→        };
 33→
 34→        // Only act when `enum` is present and `type` is absent.
 35→        if obj.contains_key("type") {
 36→            return;
 37→        }
 38→        let Some(values) = obj.get("enum").and_then(|v| v.as_array()) else {
 39→            return;
 40→        };
 41→        if values.is_empty() {
 42→            return;
 43→        }
 44→
 45→        // Collect the distinct JSON types of non-null enum values.
 46→        let mut types = BTreeSet::new();
 47→        for value in values {
 48→            match value {
 49→                serde_json::Value::Null => {}, // ignore null for type inference
 50→                serde_json::Value::Bool(_) => {
 51→                    types.insert("boolean");
 52→                },
 53→                serde_json::Value::Number(n) => {
 54→                    if n.is_f64() && !n.is_i64() && !n.is_u64() {
 55→                        types.insert("number");
 56→                    } else {
 57→                        types.insert("integer");
 58→                    }
 59→                },
 60→                serde_json::Value::String(_) => {
 61→                    types.insert("string");
 62→                },
 63→                serde_json::Value::Array(_) => {
 64→                    types.insert("array");
 65→                },
 66→                serde_json::Value::Object(_) => {
 67→                    types.insert("object");
 68→                },
 69→            }
 70→        }
 71→
 72→        // In JSON Schema, "number" subsumes "integer". When both appear
 73→        // (e.g. enum mixes 1 and 1.5), collapse to "number".
 74→        if types.contains("integer") && types.contains("number") {
 75→            types.remove("integer");
 76→        }
 77→
 78→        // Only restore when all non-null values share a single type.
 79→        if types.len() == 1 {
 80→            let inferred_type = types.into_iter().next().unwrap_or_default();
 81→            obj.insert(
 82→                "type".to_string(),
 83→                serde_json::Value::String(inferred_type.to_string()),
 84→            );
 85→        }
 86→    }
 87→}
