134→fn canonicalize_schema_for_openai_compat(schema: &serde_json::Value) -> serde_json::Value {
135→    let document = match SchemaDocument::from_json(schema) {
136→        Ok(document) => document,
137→        Err(error) => {
138→            warn!(
139→                error = %error,
140→                "openai tool schema failed Draft 2020-12 preflight; using raw schema for best-effort normalization"
141→            );
142→            return schema.clone();
143→        },
144→    };
145→
146→    if let Err(error) = document.root() {
147→        warn!(
148→            error = %error,
149→            "openai tool schema failed canonical AST resolution; using raw schema for best-effort normalization"
150→        );
151→        return schema.clone();
152→    }
153→
154→    document
155→        .canonical_schema_json()
156→        .map_or_else(
157→            |error| {
158→                warn!(
159→                    error = %error,
160→                    "openai tool schema canonicalization was unavailable; using raw schema for best-effort normalization"
161→                );
162→                schema.clone()
163→            },
164→            serde_json::Value::clone,
165→        )
166→}
