168→/// Validate and normalize a JSON Schema document into the OpenAI-compatible
169→/// function-calling subset via `json_schema_ast` canonicalization plus
170→/// recursive `schemars` transforms.
171→pub(crate) fn sanitize_schema_for_openai_compat(schema: &mut serde_json::Value) {
172→    let canonical = canonicalize_schema_for_openai_compat(schema);
173→
174→    let Ok(mut transformed) = Schema::try_from(canonical.clone()) else {
175→        *schema = canonical;
176→        return;
177→    };
178→    let mut replace_const = ReplaceConstValue::default();
179→    replace_const.transform(&mut transformed);
180→    let mut replace_unevaluated_properties = ReplaceUnevaluatedProperties::default();
181→    replace_unevaluated_properties.transform(&mut transformed);
182→    let mut replace_prefix_items = ReplacePrefixItems::default();
183→    replace_prefix_items.transform(&mut transformed);
184→    let mut remove_ref_siblings = RemoveRefSiblings::default();
185→    remove_ref_siblings.transform(&mut transformed);
186→    let mut subset_transform = RecursiveTransform(OpenAiSchemaSubsetTransform);
187→    subset_transform.transform(&mut transformed);
188→
189→    // Re-infer `"type"` from enum values after canonicalization stripped it.
190→    // Providers like Fireworks AI reject schemas without explicit type
191→    // annotations even when enum values unambiguously imply the type.
192→    let mut restore_enum_type = RecursiveTransform(RestoreEnumTypeTransform);
193→    restore_enum_type.transform(&mut transformed);
194→
195→    *schema = transformed.to_value();
196→}
