517→/// Fireworks regression: canonicalization strips `"type": "string"` from
518→/// enum properties when all enum values are strings. The post-canonicalization
519→/// `RestoreEnumTypeTransform` must re-infer and restore the type annotation
520→/// so providers like Fireworks AI don't reject the schema with 400.
521→#[test]
522→fn sanitize_restores_type_on_string_enum() {
523→    let mut schema = serde_json::json!({
524→        "type": "object",
