529→            }
530→        },
531→        "required": ["action"]
532→    });
533→
534→    sanitize_schema_for_openai_compat(&mut schema);
535→
536→    assert_eq!(
537→        schema["properties"]["action"]["type"], "string",
538→        "type must be restored after canonicalization strips it"
539→    );
