 90→/// Recursively patch schema for OpenAI strict mode compliance.
 91→///
 92→/// OpenAI's strict mode requires:
 93→/// 1. `additionalProperties: false` on every object in the schema tree
 94→/// 2. All properties must be listed in the `required` array
 95→///
 96→/// Properties not in the original `required` array are made nullable so the
 97→/// model can send `null` for unused optional fields instead of fabricating
 98→/// placeholder values.
 99→///
100→/// Schemas with `type: ["object", "string", ...]` are collapsed to
101→/// `type: "object"` because strict mode and downstream OpenAI-compatible
102→/// providers require a single concrete object type for tool schemas.
103→pub fn patch_schema_for_strict_mode(schema: &mut serde_json::Value) {
104→    let Some(obj) = schema.as_object_mut() else {
105→        return;
106→    };
107→
108→    let mut optional_props: Vec<String> = Vec::new();
109→
110→    if type_is_object(obj) {
111→        if obj.get("type").and_then(|value| value.as_array()).is_some() {
112→            obj.insert("type".to_string(), serde_json::json!("object"));
113→        }
114→
115→        obj.insert("additionalProperties".to_string(), serde_json::json!(false));
116→
117→        if let Some(props) = obj
118→            .get("properties")
119→            .and_then(|value| value.as_object())
120→            .cloned()
121→        {
122→            let originally_required: HashSet<String> = obj
123→                .get("required")
124→                .and_then(|value| value.as_array())
125→                .map(|required| {
126→                    required
127→                        .iter()
128→                        .filter_map(|entry| entry.as_str().map(String::from))
129→                        .collect()
130→                })
131→                .unwrap_or_default();
132→
133→            let all_prop_names: Vec<serde_json::Value> =
134→                props.keys().map(|name| serde_json::json!(name)).collect();
135→            obj.insert("required".to_string(), serde_json::json!(all_prop_names));
136→
137→            for key in props.keys() {
138→                if !originally_required.contains(key) {
139→                    optional_props.push(key.clone());
140→                }
141→            }
142→        } else {
143→            obj.insert("properties".to_string(), serde_json::json!({}));
144→            obj.insert("required".to_string(), serde_json::json!([]));
145→        }
146→    }
147→
148→    if let Some(props) = obj
149→        .get_mut("properties")
150→        .and_then(|value| value.as_object_mut())
151→    {
152→        for prop_schema in props.values_mut() {
153→            patch_schema_for_strict_mode(prop_schema);
154→        }
155→    }
156→
157→    if let Some(items) = obj.get_mut("items") {
158→        patch_schema_for_strict_mode(items);
159→    }
160→
161→    for key in ["anyOf", "oneOf", "allOf"] {
162→        if let Some(variants) = obj.get_mut(key).and_then(|value| value.as_array_mut()) {
163→            for variant in variants {
164→                patch_schema_for_strict_mode(variant);
165→            }
166→        }
167→    }
168→
169→    if let Some(additional) = obj.get_mut("additionalProperties")
170→        && additional.is_object()
171→    {
172→        patch_schema_for_strict_mode(additional);
173→    }
174→
175→    if !optional_props.is_empty()
176→        && let Some(props) = obj
177→            .get_mut("properties")
178→            .and_then(|value| value.as_object_mut())
179→    {
180→        for key in &optional_props {
181→            if let Some(prop_schema) = props.get_mut(key) {
182→                make_nullable(prop_schema);
183→            }
184→        }
185→    }
186→}
187→

        obj.retain(|key, _| OPENAI_ALLOWED_SCHEMA_KEYWORDS.contains(&key.as_str()));
    }
