+    // Reproduces the Attio MCP schema pattern from issue #743:
+    // nested anyOf with `not` and no `type` key, declared as draft-07.
+    let mut schema = serde_json::json!({
+        "$schema": "http://json-schema.org/draft-07/schema#",
+        "type": "object",
+        "properties": {
+            "query": {
+                "anyOf": [
+                    {
+                        "anyOf": [
+                            {
+                                "not": {
+                                    "const": ""
+                                }
+                            },
+                            {
+                                "type": "string"
+                            }
